// src/Dashboard.js
// src/Dashboard.js
import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";

export default function Dashboard() {
  const [alerts, setAlerts] = useState([]);
  const navigate = useNavigate();

  const token = localStorage.getItem("token");
  const user = JSON.parse(localStorage.getItem("user") || "{}");

  // Axios instance
  const API = axios.create({
    baseURL: "http://localhost:5000/api",
    headers: { Authorization: `Bearer ${token}` },
  });

  // Fetch Alerts
  const fetchAlerts = async () => {
    try {
      const res = await API.get("/alerts");
      setAlerts(res.data);
    } catch (error) {
      console.error(error);
      alert(error.response?.data?.message || "Failed to fetch alerts");
    }
  };

  useEffect(() => {
    if (!token) {
      alert("Please login first");
      navigate("/");
    } else {
      fetchAlerts();
    }
  }, []);

  // SOS Button
  const sendSOS = () => {
    if (!navigator.geolocation) {
      alert("Geolocation is not supported");
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        try {
          await API.post("/alerts", {
            latitude: pos.coords.latitude,
            longitude: pos.coords.longitude,
          });
          alert("SOS Sent 🚨");
          fetchAlerts();
        } catch (error) {
          console.error(error);
          alert(error.response?.data?.message || "Failed to send SOS");
        }
      },
      () => {
        alert("Location permission denied");
      }
    );
  };

  // Accept Alert
  const acceptAlert = async (id) => {
    try {
      await API.put(`/alerts/accept/${id}`);
      fetchAlerts();
    } catch (error) {
      console.error(error);
      alert("Failed to accept alert");
    }
  };

  // Resolve Alert
  const resolveAlert = async (id) => {
    try {
      await API.put(`/alerts/resolve/${id}`);
      fetchAlerts();
    } catch (error) {
      console.error(error);
      alert("Failed to resolve alert");
    }
  };

  const mapCenter = alerts.length
    ? [alerts[0].latitude, alerts[0].longitude]
    : [20.5937, 78.9629];

  return (
    <div style={{ textAlign: "center", padding: "20px" }}>
      <h1>Welcome, {user?.name}</h1>

      {user?.role === "user" && (
        <button
          onClick={sendSOS}
          style={{
            padding: "15px",
            fontSize: "18px",
            backgroundColor: "red",
            color: "white",
            border: "none",
            borderRadius: "10px",
            marginBottom: "20px",
            cursor: "pointer",
          }}
        >
          🚨 SOS
        </button>
      )}

      <h2>Emergency Alerts</h2>

      {alerts.map((alert) => (
        <div
          key={alert._id}
          style={{
            border: "1px solid #ccc",
            padding: "10px",
            margin: "10px",
          }}
        >
          <p><strong>User:</strong> {alert.userEmail}</p>
          <p><strong>Status:</strong> {alert.status}</p>
          <p>
            <strong>Location:</strong> {alert.latitude}, {alert.longitude}
          </p>

          {(user?.role === "volunteer" || user?.role === "admin") && (
            <>
              {alert.status === "pending" && (
                <button onClick={() => acceptAlert(alert._id)}>
                  Accept
                </button>
              )}
              {alert.status === "accepted" && (
                <button onClick={() => resolveAlert(alert._id)}>
                  Resolve
                </button>
              )}
            </>
          )}
        </div>
      ))}

      <h2>Live Map</h2>
      <MapContainer
        center={mapCenter}
        zoom={alerts.length ? 10 : 5}
        style={{ height: "400px", width: "80%", margin: "auto" }}
      >
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
        {alerts.map((alert) => (
          <Marker
            key={alert._id}
            position={[alert.latitude, alert.longitude]}
          >
            <Popup>
              {alert.userEmail} <br />
              Status: {alert.status}
            </Popup>
          </Marker>
        ))}
        <p>
          <strong>User:</strong> {alert.userEmail}
        </p>
      </MapContainer>
    </div>
  );
}
